               onClick={handleLogin}
               className="mt-4 inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-emerald-600 hover:bg-emerald-700"
             >
               Login as Admin
             </button>
          </div>
        )
      )}
    </Layout>
  );
};

