            )}
            {dbStatus === 'error' && (
              <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-amber-100 text-amber-800" title="Using local mock data because Supabase table 'posts' was not found or is inaccessible.">
                <WifiOff className="-ml-0.5 mr-1 h-3 w-3" />
                Using Mock Data
              </span>
            )}
          </div>
          <p className="text-sm text-gray-500 mt-2 sm:mt-0">
            Welcome back, Sarah
          </p>
        </div>

        <div className="mb-6 border-b border-gray-200">
          <nav className="-mb-px flex space-x-8 overflow-x-auto">
            <button
              onClick={() => setActiveTab('overview')}
              className={`${activeTab === 'overview' ? 'border-emerald-500 text-emerald-600' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'} whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
            >
              Overview
            </button>
            <button
              onClick={() => setActiveTab('posts')}
              className={`${activeTab === 'posts' ? 'border-emerald-500 text-emerald-600' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'} whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm`}
            >
              Content Management
            </button>
            <button
              onClick={() => setActiveTab('ai-assistant')}
              className={`${activeTab === 'ai-assistant' ? 'border-purple-500 text-purple-600' : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'} whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm flex items-center`}
            >
              <Sparkles className="h-4 w-4 mr-2" />
              AI Assistant
            </button>
          </nav>
        </div>

        {activeTab === 'overview' && <OverviewTab />}
        {activeTab === 'posts' && <PostsTab />}
        {activeTab === 'ai-assistant' && <AiAssistantTab />}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Menu, X, Leaf, LogOut } from 'lucide-react';
import { User, ViewState } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  user: User | null;
  onNavigate: (view: ViewState) => void;
  currentView: ViewState;
  onLogin: () => void;
  onLogout: () => void;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, 
  user, 
  onNavigate, 
  currentView,
  onLogin,
  onLogout
}) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const NavLink = ({ view, label }: { view: ViewState, label: string }) => (
    <button
      onClick={() => {
        onNavigate(view);
        setIsMobileMenuOpen(false);
      }}
      className={`text-sm font-semibold tracking-wide transition-colors ${
        currentView === view 
          ? 'text-emerald-800' 
          : 'text-gray-500 hover:text-emerald-700'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="min-h-screen bg-[#AABBC3] p-4 md:p-8 font-sans flex flex-col items-center">
      {/* Main App Frame */}
      <div className="w-full max-w-[1440px] bg-white rounded-[2.5rem] shadow-2xl overflow-hidden min-h-[calc(100vh-4rem)] flex flex-col relative">

        {/* Navigation */}
        <nav className="px-8 py-8 md:px-12">
          <div className="flex justify-between items-center">
            {/* Logo */}
            <div 
              className="flex items-center cursor-pointer gap-2"
              onClick={() => onNavigate('landing')}
            >
              <div className="bg-emerald-900 p-2 rounded-xl text-white">
                <Leaf className="h-5 w-5" />
              </div>
              <span className="text-xl font-bold text-gray-900 tracking-tight">Andromeda</span>
            </div>

            {/* Desktop Links */}
            <div className="hidden md:flex items-center space-x-10">
              <NavLink view="landing" label="Home" />
              <NavLink view="about" label="About us" />
              <NavLink view="library" label="Library" />
              <NavLink view="work" label="Our Work" />
              {user?.role === 'admin' && (
                <NavLink view="dashboard" label="Dashboard" />
              )}
            </div>

            {/* Auth / Action */}
            <div className="hidden md:flex items-center">
              {user ? (
                <div className="flex items-center space-x-4 bg-gray-50 px-4 py-2 rounded-full border border-gray-100">
                  <div className="flex items-center space-x-2">
                    <img className="h-8 w-8 rounded-full object-cover" src={user.avatarUrl} alt={user.name} />
                    <span className="text-sm font-semibold text-gray-700">{user.name}</span>
                  </div>
                  <button 
                    onClick={onLogout}
                    className="text-gray-400 hover:text-red-500 transition-colors"
                    title="Logout"
                  >
                    <LogOut className="h-4 w-4" />
                  </button>
                </div>
              ) : (
                <button
                  onClick={onLogin}
                  className="inline-flex items-center px-6 py-2.5 border border-transparent text-sm font-bold rounded-full text-white bg-emerald-900 hover:bg-emerald-800 transition-all hover:shadow-lg transform hover:-translate-y-0.5"
                >
                  Log In
                </button>
              )}
            </div>

            {/* Mobile Menu Button */}
            <div className="flex items-center md:hidden">
              <button
                onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                className="text-gray-500 hover:text-gray-700 focus:outline-none"
              >
                {isMobileMenuOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
              </button>
            </div>
          </div>

          {/* Mobile Menu */}
          {isMobileMenuOpen && (
            <div className="md:hidden mt-6 bg-gray-50 rounded-2xl p-6 space-y-4 animate-in slide-in-from-top-4 fade-in">
              <div className="flex flex-col space-y-4">
                <NavLink view="landing" label="Home" />
                <NavLink view="about" label="About us" />
                <NavLink view="library" label="Library" />
                <NavLink view="work" label="Our Work" />
                {user?.role === 'admin' && (
                  <NavLink view="dashboard" label="Dashboard" />
                )}
              </div>
              <div className="pt-4 border-t border-gray-200">
                {user ? (
                   <button onClick={onLogout} className="text-red-500 font-semibold text-sm">Log out</button>
                ) : (
                   <button onClick={onLogin} className="text-emerald-800 font-semibold text-sm">Log in</button>
                )}
              </div>
            </div>
          )}
        </nav>

        {/* Content Area */}
        <main className="flex-grow flex flex-col">
          {children}
        </main>

        {/* Minimal Footer */}
        {currentView !== 'dashboard' && currentView !== 'login' && (
          <footer className="px-8 md:px-12 py-8 mt-auto">
             <div className="border-t border-gray-100 pt-8 flex flex-col md:flex-row justify-between items-center text-sm text-gray-400">
                <p>&copy; 2026 Andromeda Health.</p>
                <div className="flex space-x-6 mt-4 md:mt-0">
                  <a href="#" className="hover:text-gray-600">Privacy</a>
                  <a href="#" className="hover:text-gray-600">Terms</a>
                  <a href="#" className="hover:text-gray-600">Twitter</a>
                </div>
             </div>
          </footer>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line, AreaChart, Area
} from 'recharts';
import { 
  Plus, Search, FileText, TrendingUp, Users, Clock, Eye, Sparkles, Loader2, Wifi, WifiOff, MessageSquare
} from 'lucide-react';
import { DASHBOARD_STATS, CHART_DATA } from '../services/mockData';
import { fetchPosts } from '../services/contentService';
import { generateBlogOutline } from '../services/geminiService';
import { supabase } from '../services/supabaseClient';
import { AiGenerationState, BlogPost } from '../types';

export const Dashboard: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'posts' | 'ai-assistant'>('overview');
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [isLoadingPosts, setIsLoadingPosts] = useState(false);
  const [dbStatus, setDbStatus] = useState<'checking' | 'connected' | 'error'>('checking');
  const [aiState, setAiState] = useState<AiGenerationState>({
    isLoading: false,
    content: null,
    error: null
  });
  const [aiTopic, setAiTopic] = useState('');

  useEffect(() => {
    const checkConnection = async () => {
      const { error } = await supabase.from('posts').select('count', { count: 'exact', head: true });
      if (error) {
        setDbStatus('error');
      } else {
        setDbStatus('connected');
      }
    };
    checkConnection();
  }, []);

  useEffect(() => {
    const loadPosts = async () => {
      setIsLoadingPosts(true);
      const data = await fetchPosts();
      setPosts(data);
      setIsLoadingPosts(false);
    };
    loadPosts();
  }, []);

  const handleAiGenerate = async () => {
    if (!aiTopic.trim()) return;

    setAiState({ isLoading: true, content: null, error: null });
    try {
      const result = await generateBlogOutline(aiTopic);
      setAiState({ isLoading: false, content: result, error: null });
    } catch (err) {
      setAiState({ 
        isLoading: false, 
        content: null, 
        error: "Failed to generate content. Please ensure API Key is valid." 
      });
    }
  };

  const OverviewTab = () => (
    <div className="space-y-6">
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
        {DASHBOARD_STATS.map((stat, idx) => (
          <div key={stat.label} className={`rounded-[2rem] p-6 transition-shadow hover:shadow-md ${idx === 0 ? 'bg-[#E3F2FD]' : idx === 1 ? 'bg-[#F3E5F5]' : 'bg-[#FAFAFA] border border-gray-100'}`}>
            <div className="flex items-center justify-between mb-4">
               <div className={`p-3 rounded-full ${idx === 0 ? 'bg-blue-100 text-blue-600' : idx === 1 ? 'bg-purple-100 text-purple-600' : 'bg-gray-100 text-gray-600'}`}>
                  {stat.label.includes('User') && <Users className="h-5 w-5" />}
                  {stat.label.includes('Duration') && <Clock className="h-5 w-5" />}
                  {stat.label.includes('Subscribers') && <TrendingUp className="h-5 w-5" />}
                  {stat.label.includes('Views') && <Eye className="h-5 w-5" />}
               </div>
               <span className={`text-xs font-bold px-2 py-1 rounded-full ${stat.trend === 'up' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                 {stat.change}
               </span>
            </div>
            <div>
               <div className="text-3xl font-extrabold text-gray-900">{stat.value}</div>
               <div className="text-sm font-medium text-gray-500 mt-1">{stat.label}</div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white border border-gray-100 shadow-sm rounded-[2.5rem] p-8">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-bold text-gray-900">Engagement Overview</h3>
            <select className="bg-gray-50 border-none text-sm font-medium text-gray-500 rounded-lg px-3 py-2 cursor-pointer outline-none hover:bg-gray-100">
              <option>Last 7 Days</option>
              <option>Last 30 Days</option>
            </select>
          </div>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <defs>
                  <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Area type="monotone" dataKey="views" stroke="#10b981" strokeWidth={3} fillOpacity={1} fill="url(#colorViews)" />
                <Area type="monotone" dataKey="users" stroke="#cbd5e1" strokeWidth={2} fillOpacity={0} fill="transparent" strokeDasharray="5 5"/>
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-[#FFF8E1] rounded-[2.5rem] p-8">
          <h3 className="text-xl font-bold text-gray-900 mb-6">Popular Categories</h3>
          <div className="space-y-6">
             {[
               { name: 'Basics', val: 45, color: 'bg-amber-400' },
               { name: 'Diets', val: 32, color: 'bg-amber-300' },
               { name: 'Wellness', val: 28, color: 'bg-amber-200' },
               { name: 'Recipes', val: 19, color: 'bg-amber-100' },
             ].map(item => (
               <div key={item.name}>
                 <div className="flex justify-between text-sm font-bold text-gray-700 mb-2">
                   <span>{item.name}</span>
                   <span>{item.val}%</span>
                 </div>
                 <div className="w-full bg-white/50 rounded-full h-3">
                   <div className={`${item.color} h-3 rounded-full`} style={{width: `${item.val}%`}}></div>
                 </div>
               </div>
             ))}
          </div>
          <button className="w-full mt-8 py-3 bg-amber-900 text-white rounded-xl font-bold text-sm hover:bg-amber-800 transition-colors">
            View Analytics Report
          </button>
        </div>
      </div>
    </div>
  );

  const PostsTab = () => (
    <div className="bg-white border border-gray-100 shadow-sm rounded-[2.5rem] overflow-hidden">
      <div className="px-8 py-6 border-b border-gray-100 flex flex-col sm:flex-row justify-between items-center gap-4">
        <h3 className="text-xl font-bold text-gray-900">Content Management</h3>
        <div className="flex gap-3 w-full sm:w-auto">
          <div className="relative flex-1 sm:w-64">
             <input type="text" placeholder="Search..." className="w-full pl-10 pr-4 py-2 bg-gray-50 border-none rounded-xl text-sm focus:ring-2 focus:ring-emerald-500 outline-none" />
             <Search className="w-4 h-4 text-gray-400 absolute left-3 top-3" />
          </div>
          <button className="flex items-center px-4 py-2 bg-emerald-900 text-white rounded-xl text-sm font-bold hover:bg-emerald-800 transition-colors">
            <Plus className="h-4 w-4 mr-2" />
            New
          </button>
        </div>
      </div>

      {isLoadingPosts ? (
        <div className="p-12 flex justify-center text-gray-500">
          <Loader2 className="animate-spin h-8 w-8 text-emerald-600" />
        </div>
      ) : (
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 text-gray-500 text-xs uppercase tracking-wider">
              <tr>
                <th className="px-8 py-4 font-semibold">Article</th>
